const queries = [
  // === CLUTCH.CO ===
  { q: 'site:clutch.co "AI development" OR "machine learning" OR "automation" "project" "hired"', platform: 'clutch' },
  { q: 'site:clutch.co "custom software" OR "AI" OR "automation" "looking for agency" OR "vendor" "project"', platform: 'clutch' },

  // === GOODFIRMS.CO — has real /rfp/ section ===
  { q: 'site:goodfirms.co/rfp "AI" OR "machine learning" OR "automation" OR "SaaS" OR "software"', platform: 'goodfirms' },
  { q: 'site:goodfirms.co/projects OR site:goodfirms.co/rfp "custom software" OR "AI development" OR "data pipeline"', platform: 'goodfirms' },

  // === GETPROJECTS.AI — AI-focused project board ===
  { q: 'site:getprojects.ai "AI agent" OR "LLM" OR "RAG" OR "computer vision" OR "machine learning"', platform: 'getprojects' },
  { q: 'site:getprojects.ai "automation" OR "data pipeline" OR "SaaS" OR "software development"', platform: 'getprojects' },

  // === DESIGNRUSH.COM ===
  { q: 'site:designrush.com "AI development" OR "machine learning" OR "automation" "project" OR "agency"', platform: 'designrush' },
  { q: 'site:designrush.com "software development" OR "custom software" "company" "project brief" OR "hire"', platform: 'designrush' },

  // === SORTLIST.COM ===
  { q: 'site:sortlist.com "AI" OR "machine learning" OR "automation" "project" OR "brief" OR "looking for"', platform: 'sortlist' },

  // === CREDO (GETCREDO.COM) ===
  { q: 'site:getcredo.com "AI" OR "software" OR "tech" OR "automation" "project" OR "agency" OR "service"', platform: 'credo' },

  // === UPCITY ===
  { q: 'site:upcity.com "AI development" OR "software development" OR "machine learning" "agency" OR "hire"', platform: 'upcity' },

  // === AGENCY SPOTTER ===
  { q: 'site:agencyspotter.com "AI" OR "machine learning" OR "software" OR "automation" "project" OR "brief"', platform: 'agency_spotter' },

  // === BARK.COM — actual service request listings ===
  { q: 'site:bark.com "software development" OR "AI development" OR "machine learning" OR "web app development"', platform: 'bark' },
  { q: 'site:bark.com "automation" OR "data pipeline" OR "computer vision" OR "custom software" OR "API"', platform: 'bark' },
  { q: 'site:bark.com "SaaS" OR "mobile app" OR "chatbot" OR "AI assistant" OR "ML model"', platform: 'bark' },
];
return queries.map(q => ({ json: q }));

const skipKeywords = [
  'agency profile', 'company profile', 'reviews', 'top agencies',
  'best agencies', 'find agencies', 'compare agencies', 'directory',
  'for hire', 'logo design', 'seo services', 'social media manager',
  'content writer', 'virtual assistant', 'data entry', 'graphic design',
  'video editing', 'copywriting'
];

const platformMap = {
  'clutch.co': 'clutch',
  'goodfirms.co': 'goodfirms',
  'getprojects.ai': 'getprojects',
  'designrush.com': 'designrush',
  'sortlist.com': 'sortlist',
  'getcredo.com': 'credo',
  'upcity.com': 'upcity',
  'agencyspotter.com': 'agency_spotter',
  'bark.com': 'bark'
};

const budgetPatterns = [
  /budget[:\s]+([\$\€\£][\d,k.]+[\s\w-]*)/i,
  /([\$\€\£][\d,]+(?:,\d{3})*(?:k)?(?:\s*[-–]\s*[\$\€\£]?[\d,]+(?:k)?)?(?:\s*(?:USD|EUR|GBP))?)/i,
  /(\d+[kK][\s\-–]+\d+[kK])/,
  /([\$\€\£]\d+(?:\.\d+)?[kK])/i
];

const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const searchQ = data.search_parameters?.q || '';
  const organicResults = data.organic_results || [];

  // Detect platform from query
  let platform = 'unknown';
  for (const [domain, pname] of Object.entries(platformMap)) {
    if (searchQ.includes(domain)) { platform = pname; break; }
  }

  for (const r of organicResults) {
    const link = r.link || '';
    if (!link) continue;

    // Detect platform from actual URL if unknown
    let actualPlatform = platform;
    if (actualPlatform === 'unknown') {
      for (const [domain, pname] of Object.entries(platformMap)) {
        if (link.includes(domain)) { actualPlatform = pname; break; }
      }
    }
    if (actualPlatform === 'unknown') continue;

    // Skip pure agency profile/directory pages (not project briefs)
    const skipPaths = [
      'clutch.co/agencies', 'clutch.co/directory',
      'designrush.com/agency-directory', 'designrush.com/agencies',
      'upcity.com/local', 'agencyspotter.com/agencies'
    ];
    if (skipPaths.some(p => link.includes(p))) continue;

    const id = actualPlatform + '_' + link.replace(/[^a-z0-9]/gi, '').slice(-60);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (skipKeywords.some(kw => fullText.includes(kw))) continue;

    // Extract budget from snippet
    let budget_text = '';
    for (const pat of budgetPatterns) {
      const m = (snippet + ' ' + title).match(pat);
      if (m) { budget_text = m[1]?.trim().substring(0, 80) || ''; break; }
    }

    results.push({ json: {
      title,
      description: snippet,
      source: actualPlatform,
      source_url: link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: actualPlatform,
      upvotes: 0,
      num_comments: 0,
      flair_text: 'Agency/RFP',
      budget_text,
      platform: actualPlatform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'agency' } }];
return results;

const post = $input.item.json;
if (post._empty || post._noData) return { json: post };

const apiKey = $env.GOOGLE_AI_API_KEY;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

These leads come from agency matching platforms and RFP boards (Clutch, GoodFirms, GetProjects, DesignRush, Sortlist, Bark, Credo, UpCity, AgencySpotter) — companies actively seeking a tech agency or posting project briefs.

IDEAL LEAD: A company that posted a project brief or is actively seeking a software/AI agency partner.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 1.0=explicit AI/ML/automation brief | 0.8=custom software with AI potential | 0.6=general software project | 0.3=design/marketing only | 0.0=no fit
2. budget_score: 1.0=$100K+ | 0.8=$50-100K | 0.6=$25-50K | 0.5=unknown enterprise context | 0.3=$10-25K | 0.1=<$10K
3. urgency_score: 1.0=ASAP/posted this week/now | 0.7=this month | 0.5=reviewing proposals | 0.3=exploring | 0.1=no urgency
4. win_probability: 1.0=perfect AI fit, seeking agency explicitly | 0.8=strong fit, good signals | 0.6=good fit, competitive | 0.4=tangential fit | 0.2=low fit

BUDGET ESTIMATION (ALWAYS fill estimated_budget_text, never null):
- Enterprise project brief → "$50K-$500K (enterprise scope)"
- Mid-market RFP → "$25K-$150K (mid-market)"
- Startup seeking agency → "$15K-$75K (startup scope)"
- Small business project → "$5K-$25K (SMB scope)"
- Unknown budget, enterprise context → "$50K-$200K (estimated enterprise)"
- Unknown budget, SMB context → "$10K-$50K (estimated SMB)"

COMPANY EXTRACTION: Extract company name, founder/contact name, website URL from snippet and URL. Never invent. Return null if not found.`;

const prompt = SYSTEM_PROMPT + `

Score this agency RFP/project brief. Return ONLY a single valid JSON object:
{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"client_context":"Detailed description of who the client is (company, industry, current situation)","project_context":"Detailed description of what they want built (specific technical requirements, goals)","summary":"1-2 sentence high-level summary","industry":"FinTech/HealthTech/SaaS/Manufacturing/eCommerce/General","tags":["tag1","tag2"],"reasoning":"Full detailed AI reasoning: explain each score dimension in 2-3 sentences — why this relevance score, why this budget score, why this urgency score, why this win probability.","estimated_budget_text":"$X-$Y (reason)","tech_stack":[],"company_name":null,"lead_founder_name":null,"lead_website":null}

Title: ${post.title}
Platform: ${post.source}
Description: ${(post.description||'').substring(0, 1200)}${post.budget_text ? '\nBudget: ' + post.budget_text : ''}`;

const body = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 100000, temperature: 0.2, responseMimeType: 'application/json' }
};

let s = null;
try {
  const respRaw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
    body
  });
  const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
  const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) s = JSON.parse(match[0]);
} catch(e) {}

if (!s) s = {
  relevance_score:0.4, budget_score:0.4, urgency_score:0.3, win_probability:0.3,
  client_context:'Could not extract client context',
  project_context:'Could not extract project context',
  summary:'Parse error - using defaults', industry:'General', tags:[], reasoning:'Could not parse Gemini response',
  estimated_budget_text:'$10K-$50K (estimated)', tech_stack:[],
  company_name:null, lead_founder_name:null, lead_website:null
};

const overall = Math.round(((s.relevance_score*0.35)+(s.budget_score*0.30)+(s.urgency_score*0.15)+(s.win_probability*0.20))*100)/100;
const alert_tier = overall>=0.85?'instant':overall>=0.70?'digest':overall>=0.30?'dashboard':'discard';

return { json: {
  source_id: post.source_id, title: post.title, description: post.description,
  source: post.source, source_url: post.source_url, posted_at: post.posted_at,
  author: post.author||'', subreddit: post.subreddit||post.source||'',
  upvotes: 0, num_comments: 0, flair_text: post.flair_text||'Agency/RFP',
  relevance_score: s.relevance_score, budget_score: s.budget_score,
  urgency_score: s.urgency_score, win_probability: s.win_probability,
  overall_score: overall, 
  ai_summary: s.summary, 
  client_context: s.client_context,
  project_context: s.project_context,
  industry: s.industry, ai_tags: s.tags||[], ai_reasoning: s.reasoning,
  estimated_budget_text: s.estimated_budget_text||'',
  budget_mentioned: post.budget_text || s.estimated_budget_text || '',
  tech_stack: s.tech_stack||[], company_name: s.company_name||null,
  lead_founder: s.lead_founder_name||null, lead_company: s.company_name||null,
  lead_website: s.lead_website||null, lead_contact: null,
  lead_score: Math.round(overall*10),
  alert_tier, discovered_at: new Date().toISOString(), status:'new',
  location: s.location||null, deadline_text: s.deadline_text||null,
  outreach_draft: '',
  hunter_name:'', hunter_email:'', hunter_title:'', hunter_company:''
}};

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director','manager'];
let person = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0] || null;
return [{ json: {
  ...original,
  hunter_name: person ? `${person.first_name||''} ${person.last_name||''}`.trim() : '',
  hunter_email: person?.value || '',
  hunter_title: person?.position || '',
  hunter_company: data.organization || original.lead_company || ''
}}];

return [{ json: {
  ...$input.item.json,
  hunter_name: '',
  hunter_email: '',
  hunter_title: '',
  hunter_company: ''
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));
